// Combine all items into a single text for the LLM, grouped by category
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      posts: 'No new articles found for today.',
      date: new Date().toISOString().split('T')[0],
      itemCount: 0,
      urls: []
    }
  }];
}

// Group by category
const byCategory = { official: [], blog: [], community: [] };
items.forEach(item => {
  const cat = (item.json.category || 'blog').toLowerCase();
  if (byCategory[cat]) byCategory[cat].push(item.json);
  else byCategory.blog.push(item.json);
});

let postsText = '';

const categoryNames = {
  official: 'Official Sources',
  blog: 'Blog Posts',
  community: 'Community Discussions'
};

for (const [category, posts] of Object.entries(byCategory)) {
  if (posts.length === 0) continue;
  postsText += `\n## ${categoryNames[category]}\n`;
  posts.forEach((post) => {
    postsText += `### ${post.title}\n`;
    postsText += `**Source:** ${post.source_name} | **Date:** ${post.pub_date}\n`;
    postsText += `**Link:** ${post.url}\n`;
    postsText += `**Preview:** ${post.content_snippet || 'No content'}\n\n`;
  });
}

// Collect URLs for marking as processed later
const urls = items.map(item => item.json.url);

return [{
  json: {
    posts: postsText,
    date: new Date().toISOString().split('T')[0],
    itemCount: items.length,
    urls: urls
  }
}];

const item = $input.first();
const text = item.json.output || item.json.text || '';
const date = $('Prepare for LLM').first().json.date;
const urls = $('Prepare for LLM').first().json.urls || [];

// Clean up the output for plain text audio delivery
let plainText = text
  // Remove any stray markdown formatting
  .replace(/^#{1,3}\s*/gm, '')
  .replace(/\*\*(.+?)\*\*/g, '$1')
  .replace(/\*(.+?)\*/g, '$1')
  .replace(/\[(.+?)\]\((.+?)\)/g, '$1')
  // Remove bullet points and list markers
  .replace(/^\s*[-*•]\s+/gm, '')
  .replace(/^\s*\d+\.\s+/gm, '')
  // Remove emoji (unicode emoji ranges)
  .replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{200D}\u{20E3}\u{E0020}-\u{E007F}]/gu, '')
  // Clean up extra whitespace
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{ json: { plainText, date, urls, subject: 'The Daily Dispatch - ' + date } }];
